#include <iostream>
#include <string>
using namespace std;

// 1. Створюємо КРЕСЛЕННЯ (Клас)
// Краще називати класи з Великої Літери
class Student {
public: // Відкриваємо доступ для main()
    // --- ПОЛЯ --- (Дані студента)
    string name;
    int age;
    double gpa;

    // --- МЕТОДИ --- (Поведінка студента)
    void showInfo() {
        cout << "Студент: " << name << ", Вік: " << age << endl;
        cout << "Середній бал: " << gpa << "
" << endl;
    }

    bool isExcellent() {
        if (gpa >= 4.5) return true;
        return false;
    }
};

int main() {
    // 2. Створюємо ОБ'ЄКТ (Реального студента) за кресленням "Student"
    Student s1;

    // Доступ до полів здійснюється через КРАПКУ '.'
    s1.name = "Марія Осадча";
    s1.age = 19;
    s1.gpa = 4.8;

    // Створюємо ДРУГОГО студента. Вони повністю незалежні!
    Student s2;
    s2.name = "Олег";
    s2.age = 21;
    s2.gpa = 3.2;

    cout << "--- Список ---" << endl;
    // Викликаємо методи для КОЖНОГО об'єкта окремо
    s1.showInfo();
    s2.showInfo();

    if (s1.isExcellent()) {
        cout << s1.name << " отримує підвищену стипендію!" << endl;
    }

    return 0;
}
